example:
# Wrong:
def greet():
print('hi')  # not indented

# Right:
def greet():
    print('hi')

// Wrong:
const user = null;
console.log(user.name); // Error!

// Right (optional chaining):
console.log(user?.name); // undefined — no crash

// Right (null check):
if (user) console.log(user.name);

// Wrong:
const greet = 'hello';
greet();  // string is not callable

// Right:
const greet = () => 'hello';
greet();  // ✓

// Wrong:
console.log(message); // not declared

// Right:
const message = 'Hello';
console.log(message);
